/**
 * Next.js plugin that registers the tempo-annotate loader for Webpack and
 * Turbopack. Mirrors the user-facing pattern of `@next/mdx`: a higher-order
 * function that takes plugin options, returns a function that takes the user's
 * `next.config`, and returns a new config with the plugin's loader rules
 * merged in.
 *
 * See SPEC_NEXTJS.md (in this directory) for the full design rationale.
 *
 * @example
 * ```js
 * // next.config.js
 * const tempoNextjsPlugin = require("tempo-sdk/nextjs");
 * module.exports = tempoNextjsPlugin()({ reactStrictMode: true });
 * ```
 */

import { existsSync, realpathSync } from "node:fs";
import { createRequire } from "node:module";
import { dirname, resolve } from "node:path";

import type { ElementInfo, PropValue } from "@modules/annotation";

// ---------------------------------------------------------------------------
// Types. We keep these minimal and self-contained rather than depending on
// Next.js types — the plugin file is loaded by `next.config.js` evaluation,
// before `next` itself is fully resolved in some environments.
// ---------------------------------------------------------------------------

export type ComputeAnnotatedProps = (
  info: ElementInfo,
  filepath: string,
  modifiedtsMs: number,
) => Record<string, PropValue>;

export interface TempoNextjsOptions {
  /** Path to a JS/TS module that default-exports a `ComputeAnnotatedProps`
   *  function. Resolved relative to the project root (CWD where the user
   *  invokes `next dev` / `next build`). Turbopack does not allow function-
   *  valued loader options, so this must be a path. */
  computeAnnotatedPropsModule?: string;

  /** File patterns to include. Default: `["**\/*.tsx", "**\/*.jsx"]`. */
  include?: string | RegExp | Array<string | RegExp>;

  /** File patterns to exclude. Default: `["**\/node_modules\/**"]`. */
  exclude?: string | RegExp | Array<string | RegExp>;

  /** Auto-inject `<meta name="tempo-project-root">` into JSX `<head>`.
   *  Default: `true`. */
  autoInjectRootMeta?: boolean;

  /** Run the loader during production builds too. Default: `false`. */
  productionBuild?: boolean;
}

interface TurbopackRule {
  condition?: unknown;
  loaders?: Array<{ loader: string; options?: unknown } | string>;
}

interface TurbopackConfig {
  rules?: Record<string, TurbopackRule | TurbopackRule[]>;
  [key: string]: unknown;
}

interface NextConfigLike {
  webpack?: ((config: unknown, context: { dev: boolean; [k: string]: unknown }) => unknown) | null;
  turbopack?: TurbopackConfig;
  experimental?: { turbo?: TurbopackConfig; [k: string]: unknown };
  [key: string]: unknown;
}

type NextConfigInput = NextConfigLike | undefined;

interface WebpackHookContext {
  dev: boolean;
  [key: string]: unknown;
}

interface WebpackConfigLike {
  module?: { rules?: unknown[] };
  [key: string]: unknown;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const TURBOPACK_RULE_KEY = "*.{tsx,jsx}";

const requireFromHere = createRequire(
  typeof import.meta.url === "string" && import.meta.url.length > 0
    ? import.meta.url
    : __filename,
);

function resolveLoaderPath(): string {
  // Production: dist/nextjs.{js,cjs} sits next to dist/nextjs-loader.cjs.
  // Development: source nextjs.ts sits at <pkg>/nextjs.ts; the built
  // loader is at <pkg>/dist/nextjs-loader.cjs. Try both so unit tests
  // running directly against the .ts source file still find the loader.
  for (const candidate of ["./nextjs-loader.cjs", "./dist/nextjs-loader.cjs"]) {
    try {
      return requireFromHere.resolve(candidate);
    } catch {
      // try next candidate
    }
  }
  throw new Error(
    "tempo-sdk/nextjs: could not resolve nextjs-loader.cjs. " +
      "Run `pnpm build` in the tempo-sdk package to produce the dist/ output.",
  );
}

interface NextVersionInfo {
  major: number;
  minor: number;
}

function detectNextVersion(): NextVersionInfo | null {
  try {
    const pkg = requireFromHere("next/package.json") as { version: string };
    const m = /^(\d+)\.(\d+)/.exec(pkg.version);
    if (!m) return null;
    return { major: Number(m[1]), minor: Number(m[2]) };
  } catch {
    return null;
  }
}

/** Should the wrapper write to `experimental.turbo` instead of `turbopack`? */
function useExperimentalTurbo(version: NextVersionInfo | null): boolean {
  if (!version) return false;
  if (version.major < 15) return true;
  if (version.major === 15 && version.minor < 3) return true;
  return false;
}

/** Should the wrapper omit Turbopack registration entirely? Some pre-13 versions
 *  error on unknown config keys. */
function shouldOmitTurbopack(version: NextVersionInfo | null): boolean {
  if (!version) return false;
  return version.major < 13;
}

function buildTurbopackRule(
  loaderPath: string,
  options: TempoNextjsOptions,
): TurbopackRule {
  const loaderOptions: Record<string, unknown> = {};
  if (options.computeAnnotatedPropsModule !== undefined) {
    loaderOptions.computeAnnotatedPropsModule = options.computeAnnotatedPropsModule;
  }
  if (options.autoInjectRootMeta !== undefined) {
    loaderOptions.autoInjectRootMeta = options.autoInjectRootMeta;
  }

  // {all: [{not: "foreign"}, "development"]} — exclude node_modules / Next
  // internals AND only run during `next dev`. The "development" condition is
  // a Turbopack built-in; it matches both `next dev` and `next build` in dev
  // mode but is inert during a production `next build`.
  const condition = options.productionBuild
    ? { not: "foreign" }
    : { all: [{ not: "foreign" }, "development"] };

  return {
    condition,
    loaders: [{ loader: loaderPath, options: loaderOptions }],
  };
}

function mergeTurbopackRules(
  existing: TurbopackConfig | undefined,
  newRule: TurbopackRule,
): TurbopackConfig {
  const existingRule = existing?.rules?.[TURBOPACK_RULE_KEY];
  let mergedRule: TurbopackRule | TurbopackRule[];
  if (!existingRule) {
    mergedRule = newRule;
  } else if (Array.isArray(existingRule)) {
    mergedRule = [...existingRule, newRule];
  } else {
    mergedRule = [existingRule, newRule];
  }
  return {
    ...existing,
    rules: {
      ...existing?.rules,
      [TURBOPACK_RULE_KEY]: mergedRule,
    },
  };
}

function buildWebpackHook(
  loaderPath: string,
  options: TempoNextjsOptions,
  userWebpack: NextConfigLike["webpack"],
): NonNullable<NextConfigLike["webpack"]> {
  const loaderOptions: Record<string, unknown> = {};
  if (options.computeAnnotatedPropsModule !== undefined) {
    loaderOptions.computeAnnotatedPropsModule = options.computeAnnotatedPropsModule;
  }
  if (options.autoInjectRootMeta !== undefined) {
    loaderOptions.autoInjectRootMeta = options.autoInjectRootMeta;
  }

  const allowProduction = options.productionBuild === true;

  return (configIn, context) => {
    const config = configIn as WebpackConfigLike;
    const ctx = context as WebpackHookContext;
    if (ctx.dev || allowProduction) {
      config.module ??= {};
      config.module.rules ??= [];
      config.module.rules.push({
        test: /\.(tsx|jsx)$/,
        exclude: /node_modules/,
        enforce: "pre",
        use: [{ loader: loaderPath, options: loaderOptions }],
      });
    }
    if (typeof userWebpack === "function") {
      return userWebpack(config, context);
    }
    return config;
  };
}

// ---------------------------------------------------------------------------
// tempoProjectRoot — sync helper for Pages Router users (Section 6.4)
// ---------------------------------------------------------------------------

let cachedTempoProjectRoot: string | null = null;

/**
 * Returns the canonical project root that the Tempo loader uses to compute
 * `data-tempo-filepath` values. Use this in `pages/_document.tsx` to set the
 * content of `<meta name="tempo-project-root">`, ensuring the manual meta tag
 * value matches what the loader produces.
 */
export function tempoProjectRoot(): string {
  if (cachedTempoProjectRoot !== null) return cachedTempoProjectRoot;

  // Walk upward from CWD looking for the nearest package.json. CWD is what
  // Next.js itself uses as the project root when the user invokes
  // `next dev` / `next build` — the loader's `rootContext` matches.
  let dir = process.cwd();
  // eslint-disable-next-line no-constant-condition
  while (true) {
    if (existsSync(resolve(dir, "package.json"))) break;
    const parent = dirname(dir);
    if (parent === dir) break;
    dir = parent;
  }
  let canonical = dir;
  try {
    canonical = realpathSync.native(dir);
  } catch {
    // Keep `dir` as fallback.
  }
  cachedTempoProjectRoot = canonical;
  return canonical;
}

/** Reset the cached project root. For tests only. */
export function _resetTempoProjectRoot(): void {
  cachedTempoProjectRoot = null;
}

// ---------------------------------------------------------------------------
// tempoNextjsPlugin — the wrapper
// ---------------------------------------------------------------------------

/**
 * Higher-order function that wraps a Next.js config to register the
 * tempo-annotate loader with both Webpack and Turbopack. No-op when
 * `process.env.TEMPO` is not set.
 *
 * @example
 * ```js
 * // next.config.js
 * const tempoNextjsPlugin = require("tempo-sdk/nextjs");
 * module.exports = tempoNextjsPlugin()({ reactStrictMode: true });
 * ```
 */
export function tempoNextjsPlugin(
  pluginOptions: TempoNextjsOptions = {},
): (inputConfig?: NextConfigLike) => NextConfigLike {
  return (inputConfigArg?: NextConfigLike): NextConfigLike => {
    const inputConfig: NextConfigLike = inputConfigArg ?? {};

    if (!process.env.TEMPO) return inputConfig;

    // Routed through `_internal.*` so unit tests can spy on these helpers
    // without rewiring the imports.
    const loaderPath = _internal.resolveLoaderPath();
    const version = _internal.detectNextVersion();
    const omitTurbopack = _internal.shouldOmitTurbopack(version);
    const useExperimental = _internal.useExperimentalTurbo(version);

    const newRule = buildTurbopackRule(loaderPath, pluginOptions);

    const existingTurbo = useExperimental
      ? inputConfig.experimental?.turbo
      : inputConfig.turbopack;
    const mergedTurbo = mergeTurbopackRules(existingTurbo, newRule);

    const webpackHook = buildWebpackHook(
      loaderPath,
      pluginOptions,
      inputConfig.webpack ?? null,
    );

    const next: NextConfigLike = {
      ...inputConfig,
      webpack: webpackHook,
    };

    if (!omitTurbopack) {
      if (useExperimental) {
        next.experimental = {
          ...inputConfig.experimental,
          turbo: mergedTurbo,
        };
      } else {
        next.turbopack = mergedTurbo;
      }
    }

    return next;
  };
}

export default tempoNextjsPlugin;

// ---------------------------------------------------------------------------
// Type re-exports for users writing custom strategies.
// ---------------------------------------------------------------------------

export type { ElementInfo, PropValue } from "@modules/annotation";

// Internal exports used by tests.
export const _internal = {
  buildTurbopackRule,
  mergeTurbopackRules,
  buildWebpackHook,
  detectNextVersion,
  useExperimentalTurbo,
  shouldOmitTurbopack,
  resolveLoaderPath,
};
